(window.webpackJsonp=window.webpackJsonp||[]).push([[171],{798:function(r,n){r.exports="\x3c!-- \r\ntitle: 08-Python进程\r\nsort: \r\n--\x3e \r\n# Python进程与线程\r\n\r\n> 一个任务就是一个进程。\r\n>\r\n> 进程中的子进程称为线程。\r\n\r\n## 多进程\r\n\r\n- `fork()`\r\n\r\n  > 操作系统自动复制当前进程，子进程返回0，父进程返回子进程的ID。\r\n  >\r\n  > ```python\r\n  > import os\r\n  > \r\n  > print('Process (%s) start...', % os.getpid())\r\n  > pid = os.fork()\t\t\t\t# Only work on Linux\r\n  > # 父子进程同时运行如下命令\r\n  > if pid == 0:\r\n  >     print('I am child process (%s) and my parent is %s.' % (os.getpid(), os.getppid()))\r\n  > else:\r\n  >     print('I (%s) just created a child process (%s).' % (os.getpid(), pid))\r\n  > ```\r\n  >\r\n  \r\n- multiprocessing（翻译：多种进程）\r\n  ```python\r\n  from multiprocessing import Process\t# windows使用多线程\r\n  import os\r\n  \r\n  # 子进程要执行的代码\r\n  def run_proc(name):\r\n      print('Run child process %s (%s)...' % (name, os.getpid())\r\n      # os.getppid()\t获取父进程id\r\n      \r\n  if __name__=='__main__':\r\n      print('Parent process %s.' % os.getpid())\r\n      p = Process(target=run_proc, args=('test',))\r\n      # targe 函数名\r\n      # args 元组提供参数\r\n      # kwargs 字典方式传参\r\n      print('Child process will start.')\r\n      p.daemon = True\r\n      # 主进程结束子进程自动销毁\r\n      p.start()\r\n      p.join()\r\n      # join()方法可以等待子进程结束后再继续往下运行，通常用于进程间的同步。\r\n      # 等待进程执行完毕\r\n      print('Child process end.')\r\n  '''\r\n  Parent process 10652.\r\n  Child process will start.\r\n  Run child process test (19276)...\r\n  Child process end.\r\n  '''\r\n  ```\r\n- Pool（进程池）\r\n  ```python\r\n  from multiprocessing import Pool\r\n  import os, time, random\r\n  \r\n  def long_time_task(name):\r\n      print('Run task %s (%s)...' % (name, os.getpid()))\r\n      start = time.time()\r\n      time.sleep(random.random() * 3)\r\n      end = time.time()\r\n      print('Task %s runs %0.2f seconds.' % (name, (end - start)))\r\n  \r\n  if __name__=='__main__':\r\n      print('Parent process %s.' % os.getpid())\r\n      p = Pool(4)\t\t# 同时跑四个进程\r\n      for i in range(5):\r\n          p.apply_async(long_time_task, args=(i,))\r\n      print('Waiting for all subprocesses done...')\r\n      p.close()\r\n      # 调用join()之前必须先调用close()，会等待所有子进程执行完毕。\r\n      p.join()\r\n      print('All subprocesses done.')\r\n  ```\r\n\r\n\r\n## 子进程\r\n\r\n- 在python中运行命令\r\n\r\n  ```python\r\n  import subprocess\r\n  \r\n  print('$ nslookup www.python.org')\r\n  r = subprocess.call(['nslookup', 'www.python.org'])\r\n  print('Exit code:', r)\r\n  ```\r\n\r\n### 进程间通信\r\n\r\n- 使用`Queues`来交换数据\r\n\r\n  ```python\r\n  from multiprocessing import Process, Queue\r\n  import os\r\n  import time\r\n  import random\r\n  \r\n  \r\n  def make(q):\r\n      print('My PID is %s and I am random a nember,Do you know it?' % os.getpid())\r\n      q.put(random.randint(1, 100))\r\n      time.sleep(3)\r\n  \r\n  \r\n  def guess(q):\r\n      print('My PID is %s and get the nember is %s' % (os.getpid(), q.get()))\r\n  \r\n  \r\n  if __name__ == '__main__':\r\n      q = Queue()\r\n      pm = Process(target=make, args=(q,))\r\n      pg = Process(target=guess, args=(q,))\r\n      pm.start()\r\n      pg.start()\r\n      pm.join()\r\n      pg.join()\r\n  \r\n  ```\r\n\r\n## 多线程\r\n\r\n- 可使用同一进程内的多个线程完成多功能\r\n\r\n- 启动一个线程：\r\n\r\n  把一个函数传入并创建`Thread`实例，然后调用`start()`开始执行：\r\n\r\n- 例子：\r\n\r\n  ```python\r\n  import time, threading\r\n  \r\n  # 新线程执行的代码:\r\n  def loop():\r\n      print('thread %s is running...' % threading.current_thread().name)\r\n      n = 0\r\n      while n < 5:\r\n          n = n + 1\r\n          print('thread %s >>> %s' % (threading.current_thread().name, n))\r\n          time.sleep(1)\r\n      print('thread %s ended.' % threading.current_thread().name)\r\n  \r\n  print('thread %s is running...' % threading.current_thread().name)\r\n  t = threading.Thread(target=loop, name='LoopThread')\r\n  t.setDaemon(True)\t\t# 设置守护\r\n  t.start()\r\n  t.join()\r\n  print('thread %s ended.' % threading.current_thread().name)\r\n  \r\n  '''\r\n  thread MainThread is running...\r\n  thread LoopThread is running...\r\n  thread LoopThread >>> 1\r\n  thread LoopThread >>> 2\r\n  thread LoopThread >>> 3\r\n  thread LoopThread >>> 4\r\n  thread LoopThread >>> 5\r\n  thread LoopThread ended.\r\n  thread MainThread ended.\r\n  '''\r\n  ```\r\n\r\n> 设置守护进程，主进程结束后停止子进程\r\n>\r\n> `t.setDaemon(True)`\r\n>\r\n> 传入参数\r\n>\r\n> `(target = func, args=(i, ))`\r\n\r\n### 自定义线程类\r\n\r\n```python\r\nclass TestThr(threading.Thread):\r\n    # 调用父类的init\r\n    def __init__(self):\r\n        super().__init__()\r\n    def run(self):\r\n        for i in range(5):\r\n            print(\"正在执行子线程的run方法...\", i)\r\n            time.sleep(0.5)\r\n\r\n# 创建实例对象\r\ntest = TestThr()\r\n# 启用线程\r\ntest.start()\r\n# 运行过程中不影响下面代码执行\r\nprint(\"I'm coming in.\")\r\n```\r\n\r\n### LOCK\r\n\r\n> 多进程变量互相独立，而多线程为共享。\r\n>\r\n> 任何一个变量都可以被修改。\r\n\r\n#### 使用\r\n\r\n```python\r\n# 创建锁，全局变量\r\nlock = threading.Lock()\r\n# 上锁\r\nlock.acquire()\r\n# 执行操作\r\n# 解锁\r\nlock.release()\r\n```\r\n\r\n#### 例子\r\n\r\n```python\r\nimport time\r\nimport threading\r\n\r\nbalance = 0\r\n\r\n\r\ndef change_b(n):\r\n    global balance\r\n    balance = balance + n\r\n    balance = balance - n\r\n\r\ndef run_thread(n):\r\n    for i in range(1000000):\r\n        change_b(n)\r\n\r\nt1 = threading.Thread(target=run_thread, args=(5,))\r\nt2 = threading.Thread(target=run_thread, args=(8,))\r\nt1.start()\r\nt2.start()\r\nt1.join()\r\nt2.join()\r\nprint(balance)\t\t# balance不等于0\r\n\r\n# 将t1.join()放在t2.start()前面.即可先执行t1\r\n```\r\n\r\n- 使用锁\r\n\r\n  ```python\r\n  lock = threading.Lock()\r\n  def run_thread(n):\r\n      for i in range(10000000):\r\n          lock.acquire()\r\n          change_b(n) # 修改变量函数\r\n          lock.release()\r\n  ```\r\n\r\n## ThreadLocal\r\n\r\n用于进程间通信\r\n\r\n- ```python\r\n  import threading\r\n  \r\n  Local_name = threading.local()\r\n  \r\n  \r\n  def process_staff():\r\n      name = Local_name.criminal\r\n      print('I am process %sand I konw the criminal\\'s name is %s.\\n' %\r\n            (threading.current_thread().name, name))\r\n  \r\n  \r\n  def process_thread(name):\r\n      Local_name.criminal = name\r\n      print('I am process %s. Do you konw the criminal\\'s name?\\n' %\r\n            threading.current_thread().name)\r\n      process_staff()\r\n  \r\n  t1 = threading.Thread(target=process_thread,args=(\"fzf\",),name=\"007-1\")     # 这里的name是进程名\r\n  t2 = threading.Thread(target=process_thread,args=(\"nmdxf\",),name=\"007-2\")   # 这里的name是进程名\r\n  t1.start()\r\n  t2.start()\r\n  t1.join()\r\n  t2.join()\r\n  ```\r\n\r\n> 全局变量`local_school`就是一个`ThreadLocal`对象，你可以把`local_school`看成全局变量，每个属性如`local_school.student`都是线程的局部变量，`ThreadLocal`内部会处理锁的问题。\r\n\r\n> 可以理解为全局变量`local_school`是一个`dict`，不但可以用`local_school.student`，还可以绑定其他变量，如`local_school.teacher`等等。\r\n\r\n> `ThreadLocal`最常用的地方就是为每个线程绑定一个数据库连接，HTTP请求，用户身份信息等，这样一个线程的所有调用到的处理函数都可以非常方便地访问这些资源。\r\n\r\n## 进程与线程\r\n\r\n- 进程稳定，线程快（a little)\r\n- 计算密集型用c，IO密集型用py。\r\n- 使用异步IO单进程单线程执行多任务。\r\n\r\n## 分布式进程\r\n\r\n- Thread or Process 优先选择 Process，可分布至多计算机\r\n\r\n  ```python\r\n  # master.py for windows\r\n  \r\n  import time\r\n  import queue\r\n  from multiprocessing.managers import BaseManager\r\n  from multiprocessing import freeze_support\r\n  \r\n  # 任务个数\r\n  task_number = 10\r\n  \r\n  # 定义收发队列\r\n  task_queue = queue.Queue(task_number)\r\n  result_queue = queue.Queue(task_number)\r\n  \r\n  \r\n  def gettask():\r\n      return task_queue\r\n  \r\n  \r\n  def getresult():\r\n      return result_queue\r\n  \r\n  \r\n  def test():\r\n      # windows下绑定调用接口不能使用lambda，所以只能先定义函数再绑定\r\n      BaseManager.register('get_task', callable=gettask)\r\n      BaseManager.register('get_result', callable=getresult)\r\n      # 绑定端口并设置验证码，windows下需要填写ip地址，linux下不填默认为本地\r\n      manager = BaseManager(address=('127.0.0.1', 5002), authkey=b'123')\r\n      # 启动\r\n      manager.start()\r\n      try:\r\n          # 通过网络获取任务队列和结果队列\r\n          task = manager.get_task()\r\n          result = manager.get_result()\r\n  \r\n          # 添加任务\r\n          for i in range(task_number):\r\n              print('Put task %d...' % i)\r\n              task.put(i)\r\n  \r\n          # 每秒检测一次是否所有任务都被执行完\r\n          while not result.full():\r\n              time.sleep(1)\r\n  \r\n          for i in range(result.qsize()):\r\n              ans = result.get()\r\n              print('task %d is finish , runtime:%d s' % ans)\r\n  \r\n      except:\r\n          print('Manager error')\r\n      finally:\r\n          # 一定要关闭，否则会爆管道未关闭的错误\r\n          manager.shutdown()\r\n  \r\n  \r\n  if __name__ == '__main__':\r\n      # windows下多进程可能会炸，添加这句可以缓解\r\n      freeze_support()\r\n      test()\r\n  \r\n  ```\r\n\r\n  ```python\r\n  #!/usr/bin/env python3\r\n  # -*- coding : utf-8 -*-\r\n  # task.py for windows\r\n  \r\n  import time\r\n  import sys\r\n  import queue\r\n  import random\r\n  from multiprocessing.managers import BaseManager\r\n  \r\n  BaseManager.register('get_task')\r\n  BaseManager.register('get_result')\r\n  \r\n  conn = BaseManager(address=('127.0.0.1', 5002), authkey=b'123')\r\n  \r\n  try:\r\n      conn.connect()\r\n  except:\r\n      print('连接失败')\r\n      sys.exit()\r\n  \r\n  task = conn.get_task()\r\n  result = conn.get_result()\r\n  \r\n  while not task.empty():\r\n      n = task.get(timeout=1)\r\n      print('run task %d' % n)\r\n      sleeptime = random.randint(0, 3)\r\n      time.sleep(sleeptime)\r\n      rt = (n, sleeptime)\r\n      result.put(rt)\r\n  \r\n  if __name__ == '__main__':\r\n      pass\r\n  ```\r\n  \r\n"}}]);